/**
 * Sarf (Morphology) Exercise Database
 * Word analysis exercises for classical Arabic morphology
 */

import type { ConceptReference } from './grammaticalConcepts';

export interface SarfExercise {
  id: number;
  word: string; // The Arabic word to analyze
  transliteration: string;
  category: 'verb' | 'noun' | 'active-participle' | 'passive-participle' | 'masdar' | 'adjective';
  root: string; // Root letters (جذر)
  pattern: string; // Pattern/scale (وزن) in Arabic
  patternTranslit?: string; // Pattern transliteration
  verbForm?: 'I' | 'II' | 'III' | 'IV' | 'V' | 'VI' | 'VII' | 'VIII' | 'IX' | 'X' | 'XI' | 'I-Q' | 'II-Q' | 'quad-II'; // For verbs
  meaning: string;
  usage: string; // How it's used
  prepositions?: string[]; // Prepositions that work with this word
  exampleSentence: string;
  exampleTranslation: string;
  difficulty: 'beginner' | 'intermediate' | 'advanced';
  unit?: string;
  rootType?: string; // Type of root (e.g., 'naqis-yai', 'naqis-waw', 'mithal', 'ajwaf', 'mudaaf', etc.)
  notes?: string;
  conceptReferences?: ConceptReference[];
}

